[Form]
public class FWFTextBlockGroupAssignPanel extends FormRun
{
    SysListPanelRelationTableCallback	sysListPanel;
    FWFTextBlockModule					module;
    str 10								groupId;

}

    private container selectedReferences()
    {
        return FWFTextBlockGroupAssign::selectedReferences(
            FWFTextBlockGroup.Id,
			module);
    }

private container availableReferences()
{
    return FWFTextBlockGroupAssign::availableReferences(
        FWFTextBlockGroup.Id,
        module);
}

    public void init()
    {
        #ResAppl

        tableId		dataTable;
        fieldId		dataField;
        int         imageId = 0;
        container	columns = [0, 0];

        if (element.args().parmEnumType() == enumNum(FWFTextBlockModule))
        {
            module = element.args().parmEnum();
        }

        switch (module)
        {
            case FWFTextBlockModule::Customer:
                dataTable	= tableNum(CustTable);
                dataField	= fieldNum(CustTable, AccountNum);
                imageId		= #ImageCustomer;
                break;

            case FWFTextBlockModule::Supplier:
                dataTable	= tableNum(VendTable);
                dataField	= fieldNum(VendTable, AccountNum);
                imageId		= #ImageVendor;
                break;

            case FWFTextBlockModule::ReleasedProduct:
                dataTable	= tablenum(InventTable);
                dataField	= fieldnum(InventTable, ItemId);
                imageId		= #ImageItem;
                break;

            case FWFTextBlockModule::Project:
                dataTable	= tablenum(ProjTable);
                dataField	= fieldnum(ProjTable, ProjId);
                imageId		= #ImageItem;
                break;

        }

        sysListPanel = SysListPanelRelationTableCallback::newForm(
                             element,
                             element.controlId(formControlStr(FWFTextBlockGroupAssignPanel, ListPanelGroup)),
                             "@FWFTextBlock:AssignGroupsSelected",
                             "@FWFTextBlock:AssignGroupsRemaining",
                             imageId,
							 tablenum(FWFTextBlockGroupAssign),
                             fieldnum(FWFTextBlockGroupAssign, RefId),
                             fieldnum(FWFTextBlockGroupAssign, GroupId),
                             dataTable,
                             dataField,
                             columns,
                             0,
                             '',
                             '',
							 identifierStr(selectedReferences),
                             identifierStr(availableReferences));

        super();

        if (module)
        {
            FWFTextBlockGroup_ds.query().dataSourceTable(tableNum(FWFTextBlockGroup)).addRange(fieldNum(FWFTextBlockGroup, Module)).value(QueryValue(module));
        }

        sysListPanel.init();
    }

void tabChanged(int fromTab, int toTab)
{
    #define.TabGroupOverview(1)
    #define.TabGroupMembers(2)

    groupId = fwfTextBlockGroup.Id;
    switch (toTab)
    {
        case #TabGroupOverview:
            break;
        case #TabGroupMembers:
            sysListPanel.parmRelationRangeValue(fwfTextBlockGroup.Id);
            sysListPanel.parmRelationRangeRecId(fwfTextBlockGroup.RecId);
            sysListPanel.fill();
            break;
    }
}

boolean validate(userId _userId, AddRemove _addRemove, SysListPanelRelationTable _listViewHandler)
{
    return true;
}

int active()
{
    int ret;

    ret = super();
    element.tabChanged(0, tab.tab());
    return ret;
}

void tabChanged(int fromTab, int toTab)
{
    element.tabChanged(fromTab, toTab);
    super(fromTab, toTab);
}
